import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { Trash2, Store, Plus, X, MapPin } from 'lucide-react';

// Configuración de Iconos de Leaflet
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: markerIcon,
    shadowUrl: markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

const Dashboard = () => {
  // Estado para los locales y el Modal
  const [locales, setLocales] = useState([
    { id: 1, nombre: "Mr. Drink", direccion: "Av. Manuel Belgrano 2800, T4000 San Miguel de Tucumán", coords: [-26.816, -65.230] },
    { id: 2, nombre: "Mr. Drink 2", direccion: "Av. Sarmiento 356", coords: [-26.820, -65.200] }
  ]);
  const [showModal, setShowModal] = useState(false);
  const [nuevoLocal, setNuevoLocal] = useState({ nombre: '', direccion: '', coords: [-26.816, -65.216] });

  const agregarLocal = (e) => {
    e.preventDefault();
    const id = locales.length + 1;
    setLocales([...locales, { ...nuevoLocal, id }]);
    setShowModal(false); // Cerrar al terminar
    setNuevoLocal({ nombre: '', direccion: '', coords: [-26.816, -65.216] });
  };

  const eliminarLocal = (id) => {
    setLocales(locales.filter(l => l.id !== id));
  };

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', overflow: 'hidden', position: 'relative' }}>
      
      {/* SIDEBAR IZQUIERDA */}
      <div style={sidebarStyle}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '5px' }}>Mis Locales</h2>
        <p style={{ color: '#64748b', marginBottom: '30px' }}>Gestiona tus puntos de venta</p>

        <div style={listaContenedor}>
          {locales.map(local => (
            <div key={local.id} style={cardLocal}>
              <div style={iconBox}><Store size={20} color="#e67e22" /></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ margin: 0, fontWeight: 'bold' }}>{local.nombre}</h4>
                <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>{local.direccion}</p>
              </div>
              <button onClick={() => eliminarLocal(local.id)} style={btnBorrar}><Trash2 size={18} /></button>
            </div>
          ))}
        </div>

        <button onClick={() => setShowModal(true)} style={btnNuevaSucursal}>
          <Plus size={20} /> Nueva Sucursal
        </button>
      </div>

      {/* MAPA */}
      <div style={{ flex: 1 }}>
        <MapContainer center={[-26.8167, -65.2167]} zoom={14} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup><strong>{local.nombre}</strong><br/>{local.direccion}</Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* MODAL DE NUEVA SUCURSAL (Estilo de tu imagen) */}
      {showModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3>Agregar Nueva Sucursal</h3>
              <X onClick={() => setShowModal(false)} style={{ cursor: 'pointer' }} />
            </div>
            <form onSubmit={agregarLocal}>
              <label style={labelStyle}>Nombre del Local</label>
              <input 
                style={inputStyle} 
                placeholder="Ej: Mr. Drink 3" 
                required
                onChange={(e) => setNuevoLocal({...nuevoLocal, nombre: e.target.value})}
              />
              
              <label style={labelStyle}>Dirección Completa</label>
              <input 
                style={inputStyle} 
                placeholder="Calle, Número, Ciudad" 
                required
                onChange={(e) => setNuevoLocal({...nuevoLocal, direccion: e.target.value})}
              />

              <div style={infoBox}>
                <MapPin size={16} color="#e67e22" />
                <span>Las coordenadas se fijarán en el centro de tu ciudad actual.</span>
              </div>

              <button type="submit" style={btnNuevaSucursal}>Guardar Sucursal</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

/* --- ESTILOS EXTRA --- */
const sidebarStyle = { width: '400px', padding: '40px 25px', background: '#ffffff', display: 'flex', flexDirection: 'column', borderRight: '1px solid #e2e8f0' };
const listaContenedor = { flex: 1, overflowY: 'auto' };
const cardLocal = { display: 'flex', alignItems: 'center', padding: '20px', background: '#fff9f5', borderRadius: '16px', marginBottom: '15px', border: '1px solid #ffeada', gap: '15px' };
const iconBox = { background: '#ffffff', padding: '10px', borderRadius: '12px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' };
const btnBorrar = { background: 'transparent', border: 'none', color: '#f87171', cursor: 'pointer' };
const btnNuevaSucursal = { background: '#e67e22', color: 'white', padding: '15px', borderRadius: '12px', border: 'none', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', cursor: 'pointer', width: '100%' };

// Estilos del Modal
const modalOverlay = { position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '30px', borderRadius: '20px', width: '400px', boxShadow: '0 10px 25px rgba(0,0,0,0.2)' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '5px', fontSize: '0.9rem', fontWeight: '600', color: '#1e293b' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '20px', borderRadius: '10px', border: '1px solid #ddd', boxSizing: 'border-box' };
const infoBox = { display: 'flex', gap: '10px', background: '#f8fafc', padding: '10px', borderRadius: '10px', fontSize: '0.8rem', color: '#64748b', marginBottom: '20px' };

export default Dashboard;
